#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932
#define M_CONST 2147483647
#define A_CONST 1103515245
#define C_CONST 12345

inline double roundDouble_like(double value) {
    int newValue = (int)(value);
    if (0.5 > value - (double)newValue) return (double)newValue;
    else return (double)newValue; // preserves original behavior of `return newValue++;`
}

inline double randu_like(__global int *seed, int index) {
    int num = A_CONST * seed[index] + C_CONST;
    seed[index] = num % M_CONST;
    return fabs((double)seed[index] / (double)M_CONST);
}

inline double randn_like(__global int *seed, int index) {
    double u = randu_like(seed, index);
    double v = randu_like(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

__kernel void likelihood_kernel(__global double *arrayX,
                                __global double *arrayY,
                                __global double *xj,
                                __global double *yj,
                                __global double *CDF,
                                __global int *ind,
                                __global int *objxy,
                                __global double *likelihood,
                                __global unsigned char *I,
                                __global double *u,
                                __global double *weights,
                                int Nparticles,
                                int countOnes,
                                int max_size,
                                int k,
                                int IszY,
                                int Nfr,
                                __global int *seed,
                                __global double *partial_sums,
                                __local double *buffer) {
    (void)CDF;
    (void)u;
    (void)buffer;

    int gid = (int)get_global_id(0);
    if (gid >= Nparticles) {
        if (gid < (int)get_global_size(0)) partial_sums[gid] = 0.0;
        return;
    }

    arrayX[gid] = xj[gid] + 1.0 + 5.0 * randn_like(seed, gid);
    arrayY[gid] = yj[gid] - 2.0 + 2.0 * randn_like(seed, gid);

    double lik = 0.0;
    for (int y = 0; y < countOnes; y++) {
        int indX = (int)roundDouble_like(arrayX[gid]) + objxy[y * 2 + 1];
        int indY = (int)roundDouble_like(arrayY[gid]) + objxy[y * 2];
        int idx = (int)fabs((double)(indX * IszY * Nfr + indY * Nfr + k));
        if (idx >= max_size) idx = 0;
        ind[gid * countOnes + y] = idx;

        double val = (double)I[idx];
        lik += ((val - 100.0) * (val - 100.0) - (val - 228.0) * (val - 228.0)) / 50.0;
    }
    lik = lik / (double)countOnes;
    likelihood[gid] = lik;

    weights[gid] = weights[gid] * exp(lik);
    partial_sums[gid] = weights[gid];
}

