#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define M_CONST 2147483647
#define A_CONST 1103515245
#define C_CONST 12345

inline double randu_norm(__global int *seed, int index) {
    int num = A_CONST * seed[index] + C_CONST;
    seed[index] = num % M_CONST;
    return fabs((double)seed[index] / (double)M_CONST);
}

__kernel void sum_kernel(__global double *partial_sums, int Nparticles) {
    if (get_global_id(0) != 0) return;

    double s = 0.0;
    for (int i = 0; i < Nparticles; i++) s += partial_sums[i];
    partial_sums[0] = s;
}

__kernel void normalize_weights_kernel(__global double *weights,
                                       int Nparticles,
                                       __global double *partial_sums,
                                       __global double *CDF,
                                       __global double *u,
                                       __global int *seed) {
    if (get_global_id(0) != 0) return;

    double sumWeights = partial_sums[0];
    if (sumWeights == 0.0) sumWeights = 1.0;

    for (int i = 0; i < Nparticles; i++) {
        weights[i] = weights[i] / sumWeights;
    }

    if (Nparticles > 0) {
        CDF[0] = weights[0];
        for (int i = 1; i < Nparticles; i++) CDF[i] = CDF[i - 1] + weights[i];
    }

    double u1 = (1.0 / (double)Nparticles) * randu_norm(seed, 0);
    for (int i = 0; i < Nparticles; i++) {
        u[i] = u1 + ((double)i / (double)Nparticles);
    }
}

