#pragma OPENCL EXTENSION cl_khr_fp64 : enable

inline int findIndex_dev(__global double *CDF, int lengthCDF, double value) {
    int index = -1;
    for (int x = 0; x < lengthCDF; x++) {
        if (value <= CDF[x]) {
            index = x;
            break;
        }
    }
    if (index == -1) return lengthCDF - 1;
    return index;
}

__kernel void find_index_kernel(__global double *arrayX,
                                __global double *arrayY,
                                __global double *CDF,
                                __global double *u,
                                __global double *xj,
                                __global double *yj,
                                __global double *weights,
                                int Nparticles) {
    if (get_global_id(0) != 0) return;

    for (int j = 0; j < Nparticles; j++) {
        int i = findIndex_dev(CDF, Nparticles, u[j]);
        if (i == -1) i = Nparticles - 1;
        xj[j] = arrayX[i];
        yj[j] = arrayY[i];
    }

    double w = 1.0 / (double)Nparticles;
    for (int x = 0; x < Nparticles; x++) {
        arrayX[x] = xj[x];
        arrayY[x] = yj[x];
        weights[x] = w;
    }
}
